@spec tm_tuning_spec  src=tests/specs/tm_tuning_spec.lua  loc=883  sha=14993a2  cases=24
@exercises trackerManager (h.tm), midiManager (h.fm)
@surface   tm:addEvent, tm:flush, fm:dump, tm:getChannel, tm:assignEvent, tm:rebuild, tm:deleteEvent
@harness   mk{seed.ccs, seed.notes}

# Intent
  Exercises tm's detune/pb realisation. Invariants:
    - view layer speaks intent (note.detune); tm realises via raw pb.
    - a col-1 note with non-zero detune seats a "fake" pb absorbing the step.
    - clearing detune back to prevailing cleans up the fake pb.
    - at every seat P: logicalAt(P) = rawAt(P) - detuneAt(P), and a fake
      pb carries `fake=true` (persisted as cc metadata).

# Helpers
  @fn cents2raw(c)  @ 11
      -- pbRange default = 2 semitones = 200 cents total. So cents 50 → raw 2048.
  @fn findNote(dump, pitch)  @ 13-17
  @fn pbsAt(dump, ppq)  @ 19-25

# Cases
  @case 'adding a note with detune seats a fake pb at the note'  [harness]  @ 29-47
  @case 'logical pb at the note seat is zero (detune absorbs the raw step)'  [harness]  @ 51-68
  @case 'clearing detune back to 0 removes the fake pb'  [harness]  @ 72-91
  @case 'first lane-1 note anchors a pb-active channel even at detune 0'  [harness]  @ 97-114
  @case 'a pristine all-zero channel seats no anchor'  [harness]  @ 118-127
  @case 'two notes with different detunes produce stepwise pbs between them'  [harness]  @ 131-154
  @case 'mutating a note past a same-channel neighbour keeps fake pbs fake'  [harness]  @ 167-202
  @case 'pb.derived survives a rebuild (persisted as cc metadata)'  [harness]  @ 206-225
  @case 'deleting a detuned note cleans up its fake pb'  [harness]  @ 229-246
  @case 'a real (user-authored) pb at a note seat suppresses fake-pb bookkeeping'  [harness]  @ 250-276
  @case 'overwriting middle of A A B with B (different detunes) drops the now-redundant fake pb'  [harness]  @ 287-330
  @case 'inserting B between A and B drops the now-redundant fake pb at the existing B'  [harness]  @ 337-364
  @case 'A A A then B A A then B B A keeps the fake-pb invariant at every note seat'  [harness]  @ 372-426
  @case 'moving a detuned note past a same-detune neighbour seats absorber at the unmasked seat'  [harness]  @ 439-485
  @case 'deleting middle B in A B A drops the now-redundant fake pb at row 3'  [harness]  @ 492-519
  @case 'lane-2 detuned note seats no pb (lane-1 monopoly on realisation)'  [harness]  @ 525-549
  @case 'deleting a lane-2 note at a lane-1 fake-pb seat leaves the absorber intact'  [harness]  @ 556-594
  @case 'pure delay change shifts the fake pb with its host (count and value preserved)'  [harness]  @ 601-638
  @case 'editing a real pb does not retro-mutate any note detune'  [harness]  @ 644-676
  @case 'detune update on a note seated atop a real pb leaves it real'  [harness]  @ 682-712
  @case 'flush + rebuild + flush is idempotent on the pb dump'  [harness]  @ 719-758
  @case 'editing a lane-2 note detune does not seat or move any pb'  [harness]  @ 764-796
  @case 'negative delay reorders lane-1 hosts; absorbers seat at realised ppqs'  [harness]  @ 805-841
  @case 'foreign pb (no cents sidecar) back-derives cents; survives detune edit'  [harness]  @ 849-881

